import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from '@radikal/ui';

interface Props {
  message?: string;
  className?: string;
}

/**
 * Small info icon with a tooltip that explains the field was auto-generated
 * from the website analysis. Clicking/editing the parent field remains possible.
 */
export function AutoGeneratedHint({
  message = 'Generado automáticamente al analizar tu sitio. Puedes editarlo.',
  className,
}: Props) {
  return (
    <TooltipProvider delayDuration={150}>
      <Tooltip>
        <TooltipTrigger asChild>
          <span
            tabIndex={0}
            role="img"
            aria-label={message}
            className={
              'material-symbols-outlined text-[16px] text-slate-400 hover:text-slate-600 cursor-help align-middle ' +
              (className ?? '')
            }
          >
            info
          </span>
        </TooltipTrigger>
        <TooltipContent className="max-w-[240px] leading-relaxed">
          {message}
        </TooltipContent>
      </Tooltip>
    </TooltipProvider>
  );
}
